INSERT INTO public.photos VALUES (25563, 'Puente de Piedra 1981', 'En mayo de 1981 se procediâ”śâ”‚ a la retirada del cauce del Ebro del autobâ”śâ•‘s que habâ”śÂˇa caâ”śÂˇdo allâ”śÂˇ en diciembre de 1971, eso sâ”śÂˇ, bastante demediado 10 aâ”śâ–’os despuâ”śÂ®s. La mitologâ”śÂˇa zaragozana se alimentâ”śâ”‚ de aquel accidente, atribuyendo al pozo de San Lâ”śĂ­zaro conexiones con otras dimensiones. Al fondo, el Pilar. Fuente: turiasona.blogspot.com/', 1981, 1981, 1981, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65769600, -0.87471300, '0101000020E6100000815A0C1EA6FDEBBFE25AED612FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31600384503.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31600384503.webp', 'https://www.flickr.com/photos/zaragozaantigua/31600384503/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25565, 'Puente de Piedra 2010', 'Foto: Oliver Duch. 6 de octubre de 2010. Actuaciâ”śâ”‚n musical del saxofonista Carlos Calvo y el tubista Javier Garcâ”śÂˇa, aprovechando la reverberaciâ”śâ”‚n del arco norte del puente de Piedra. Tambiâ”śÂ®n cantâ”śâ”‚ Juncal Pibernat, en el marco de las fiestas del Arrabal. Los intâ”śÂ®rpretes llegaron en barcaza. Al fondo, el puente de Hierro. Fuente: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65790400, -0.87498100, '0101000020E610000050E27327D8FFEBBF2CF4C13236D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32910873544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32910873544.webp', 'https://www.flickr.com/photos/zaragozaantigua/32910873544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23776, 'Torre Clavero 1994', 'Aspecto de la Torre Clavero, en el barrio rural de Movera. Se trataba de una edificaciâ”śâ”‚n rural mudâ”śÂ®jar del siglo XV, derribada en abril de 2009. Fuente: Colecciâ”śâ”‚n particular.', 1994, 1994, 1994, 'Anos 90', NULL, 41.66192500, -0.83605900, '0101000020E6100000CBD8D0CDFEC0EABFD0B359F5B9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32928573651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32928573651.webp', 'https://www.flickr.com/photos/zaragozaantigua/32928573651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25568, 'Râ”śÂˇo Ebro c.1986', 'Vista capturada en altura desde la torre de San Francisco de Borja del templo del Pilar con un interesante panorama ribereâ”śâ–’o de la â”śÂ®poca. En el centro, el medieval puente de Piedra soportando intensa la circulaciâ”śâ”‚n rodada sobre un râ”śÂˇo Ebro chocolateado por la carga de materiales sedimentarios en â”śÂ®poca de crecida. Tras â”śÂ®l, el moderno puente del Pilar o de Hierro. A la izquierda y entre ambos puentes, parte del antiguo barrio del Arrabal vertebrado en torno a la calle de Jesâ”śâ•‘s. A la derecha e inmediato, el Club Nâ”śĂ­utico. Pocos aâ”śâ–’os despuâ”śÂ®s, estos puentes serâ”śÂˇan objeto de sendas intervenciones, y al fondo se les aâ”śâ–’adirâ”śÂˇa el nuevo puente de la Uniâ”śâ”‚n para dar continuidad al segundo cinturâ”śâ”‚n de ronda. Fuente visual: foto giuseppedibari, en www.flickr.com', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65734300, -0.87523600, '0101000020E6100000F70489EDEE01ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42808018575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42808018575.webp', 'https://www.flickr.com/photos/zaragozaantigua/42808018575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25574, 'Puente de Piedra c.1934', 'El puente de Piedra en una imagen capturada desde la margen derecha con una vista que hacia el fondo alcanza hasta el Arrabal, donde despuntan los remates de las torrecillas de la iglesia de Nâ”¬Â¬. Sâ”¬Â¬. de Altabâ”śĂ­s. Sobre el puente, fluida circulaciâ”śâ”‚n peatonal y un tranvâ”śÂˇa haciendo su ruta hacia la margen izquierda (bien de la lâ”śÂˇnea 4. Arrabal o de la lâ”śÂˇnea 9. Gâ”śĂ­llego). El canicular nivel del râ”śÂˇo Ebro deja al descubierto el empedrado de sillerâ”śÂˇa que protege el basamento de las pilas del puente, y sobre ellas puede verse algâ”śâ•‘n pescador y unos pardales que hasta allâ”śÂˇ han llegado caminando. El fotâ”śâ”‚grafo titulâ”śâ”‚ esta imagen de forma un tanto exagerada "Stone bridge piers" (muelles del puente de piedra).', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65694600, -0.87581600, '0101000020E61000007D08AA46AF06ECBF779E78CE16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51756392091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51756392091.webp', 'https://www.flickr.com/photos/zaragozaantigua/51756392091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26020, 'Arrabal 1938', 'Aâ”śÂ®rea vista que recoge un buen sector del Arrabal, desde el Ebro y el puente de Piedra, pasando por el cuartel de San Lâ”śĂ­zaro, el convento de las franciscanas junto a la iglesia de Altabâ”śĂ­s, la estaciâ”śâ”‚n del Norte, el arranque de la carretera de Cataluâ”śâ–’a, y la azucarera del Rabal. La imagen ha sido capturada desde el vuelo de un Junkers Ju-52 (T-2), alemâ”śĂ­n aparato utilizado como bombardero diurno por la Legiâ”śâ”‚n Câ”śâ”‚ndor desde su base de operaciones militares del Aerâ”śâ”‚dromo Sanjurjo (Garrapinillos), en apoyo a los nacionalistas durante la guerra de 1936-1939. Fuente visual: www.todocoleccion.net/', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25668129935.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25668129935.webp', 'https://www.flickr.com/photos/zaragozaantigua/25668129935/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20917, 'Felipe II c.1585', '"Felipe II ante el retrato y las hijas del Duque de Villahermosa, D. Martâ”śÂˇn de Gurrea y Aragâ”śâ”‚n, en el convento de Santo Domingo, en Zaragoza", â”śâ”‚leo de Enrique Mâ”śÂ®lida, ca. 1880.', 1585, 1585, 1585, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65798500, -0.88849900, '0101000020E610000025EB7074956EECBF18213CDA38D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19221236550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19221236550.webp', 'https://www.flickr.com/photos/zaragozaantigua/19221236550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20923, 'Almacâ”śÂ®n de la Sal 1760', 'Corte interior y exterior del arfolâ”śÂˇ (sic) principal de Zaragoza. Francisco de Velasco y Juliâ”śĂ­n de Yarza, 1760. Alzado del nuevo edificio del alfolâ”śÂˇ o almacâ”śÂ®n de la Sal de Zaragoza, construido en el solar del anterior, en el camino de la Ribera y con traseras a la calle Bonaire (luego Abâ”śÂ®n Aire), que permaneciâ”śâ”‚ en pie hasta el â”śâ•‘ltimo tercio del siglo XX en su ubicaciâ”śâ”‚n del paseo de Echegaray y Caballero 29, luego 86-88, actual 84. El acceso del mineral, procedente de Remolinos y otras canteras, se realizaba mediante barcas a travâ”śÂ®s de una mina o tâ”śâ•‘nel desde el râ”śÂˇo Ebro hasta el alfolâ”śÂˇ, a la altura del hueco de la izquierda del edificio, bajo las escaleras. Fuente: Archivo General de Simancas. Ministerio de Cultura de Espaâ”śâ–’a.', 1760, 1760, 1760, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65786700, -0.88343300, '0101000020E61000001FA166481545ECBF0F0F61FC34D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20479807868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20479807868.webp', 'https://www.flickr.com/photos/zaragozaantigua/20479807868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20981, 'Palacio de la Inquisiciâ”śâ”‚n 1820', '"The Holy Office of Zaragoza being plundered by the people in March 1820", grabado que representarâ”śÂˇa el saqueo de la sede de la Inquisiciâ”śâ”‚n de Zaragoza, situado en el palacio de Villahermosa de la calle de Predicadores entre 1760 y 1820. La imagen mostrarâ”śÂˇa las traseras del edificio en la ribera del Ebro, con el puente de piedra al fondo. 1820 fue la fecha en que se aboliâ”śâ”‚ la Inquisiciâ”śâ”‚n en Espaâ”śâ–’a por tercera vez, hasta que lo fue definitivamente en 1834. Fuente: www.akg-images.co.uk/', 1820, 1820, 1820, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65812400, -0.88523600, '0101000020E610000049BDA772DA53ECBF3A5B40683DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20883737561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20883737561.webp', 'https://www.flickr.com/photos/zaragozaantigua/20883737561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20999, 'Calle de Predicadores c.1855', 'Dibujo de Valentâ”śÂˇn Carderera centrado en la monumental escalera de acceso al piso superior de la que fuera casa de los duques de Villahermosa en la antigua calle de Predicadores, habilitada en 1842 como câ”śĂ­rceles pâ”śâ•‘blicas. Este singular espacio interior desapareciâ”śâ”‚ luego por derribo. Fuente visual: Archivo Palacio Villahermosa (Pedrola), en Manuel Garcâ”śÂˇa Guatas, Los â”śĂ­lbumes de Pedrola. Apuntes y acuarelas de Valentâ”śÂˇn Carderera en los â”śĂ­lbumes del palacio de los Duques de Villahermosa de Pedrola, IFC, 2017.', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65757300, -0.88504100, '0101000020E6100000F6CFD3804152ECBFC6DD205A2BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40075399274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40075399274.webp', 'https://www.flickr.com/photos/zaragozaantigua/40075399274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21125, 'Calle de la Democracia c.1889', 'Imagen centrada en el rotundo ingreso principal a la antigua casa de los duques de Villahermosa desde la calle de la Democracia. La placa sobre la puerta informa de la funciâ”śâ”‚n efectiva dada a este emblemâ”śĂ­tico lugar desde 1842: câ”śĂ­rceles pâ”śâ•‘blicas o nacionales. Al fondo, el patio que daba acceso a las dependencias carcelarias, con notable y animado trasiego de visitas. Esta gran casa del siglo XVI, remodelada en el XVII, ejerciâ”śâ”‚ en el siglo de Las Luces funciones militares (cuartel de caballerâ”śÂˇa), y luego soportâ”śâ”‚ la sede del Tribunal de la Inquisiciâ”śâ”‚n. Desde 1821 era de propiedad municipal, cedida por el Estado para câ”śĂ­rceles nacionales y juzgados. Fuente visual: Archivo Palacio Villahermosa (Pedrola), en Manuel Garcâ”śÂˇa Guatas, Los â”śĂ­lbumes de Pedrola. Apuntes y acuarelas de Valentâ”śÂˇn Carderera en los â”śĂ­lbumes del palacio de los Duques de Villahermosa de Pedrola, IFC, 2017.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65757300, -0.88504100, '0101000020E6100000F6CFD3804152ECBFC6DD205A2BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39981705274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39981705274.webp', 'https://www.flickr.com/photos/zaragozaantigua/39981705274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21128, 'Câ”śĂ­rceles pâ”śâ•‘blicas c.1889', 'Luminosa imagen del patio interior principal de la antigua casa de los duques de Villahermosa en el nâ”¬â•‘ 64 de la calle de la Democracia, habilitada como câ”śĂ­rceles pâ”śâ•‘blicas o nacionales. Hacia la izquierda, cercano al paseo del Ebro, se accedâ”śÂˇa a un patio secundario que se convertâ”śÂˇa en el escenario donde se instalaba el patâ”śÂˇbulo para ejecuciâ”śâ”‚n de los reos a pena de muerte. Fuente visual: Archivo Palacio Villahermosa (Pedrola), en Manuel Garcâ”śÂˇa Guatas, Los â”śĂ­lbumes de Pedrola. Apuntes y acuarelas de Valentâ”śÂˇn Carderera en los â”śĂ­lbumes del palacio de los Duques de Villahermosa de Pedrola, IFC, 2017.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65782900, -0.88498800, '0101000020E61000004147AB5AD251ECBF21AE9CBD33D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40734376231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40734376231.webp', 'https://www.flickr.com/photos/zaragozaantigua/40734376231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21279, 'Vista San Pablo c.1905', 'Postal de la Fototipia "Madriguera" (Barcelona), de la serie "Zaragoza", con el nâ”śâ•‘mero 48, titulada "Vista panorâ”śĂ­mica del Ebro". Vista del barrio de San Pablo desde la torre de su iglesia. Destaca en el centro la Casa de Amparo, en construcciâ”śâ”‚n. Al fondo, puente del Ferrocarril sobre el râ”śÂˇo Ebro. Fuente: www.ebay.es', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65781900, -0.88796600, '0101000020E6100000CCB73EAC376AECBFFED7B96933D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24573555199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24573555199.webp', 'https://www.flickr.com/photos/zaragozaantigua/24573555199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21281, 'Puente del ferrocarril 1900', 'Postal "Zaragoza. Puente del ferrocarril sobre el Ebro", editada y publicada por la fototipia de Lucas Escolâ”śĂ­ para la Uniâ”śâ”‚n Postal Universal. En la imagen, el puente del ferrocarril de 1870, recrecido en 1879, capturado desde la orilla derecha del râ”śÂˇo, inmediata al desagâ”śâ•ťe de la acequia de la Almozara, donde los Viveros del Ayuntamiento. Al otro lado, la margen izquierda, con la pequeâ”śâ–’a arboleda de la Hortilla y el desemboque de la acequia del mismo nombre.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.66154300, -0.88990800, '0101000020E61000004F5C8E57207AECBFE9F2E670ADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24733190025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24733190025.webp', 'https://www.flickr.com/photos/zaragozaantigua/24733190025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21486, 'P.â”¬â•‘ del Ebro 1926', 'Imagen capturada junto al nâ”śâ•‘mero 29 del terroso paseo del Ebro, donde perduraba el ilustrado y dieciochesco edificio del antiguo Almacâ”śÂ®n o Pâ”śâ”‚sito de la Sal de la ciudad, en desuso de esas funciones desde hacâ”śÂˇa tiempo. En el momento de realizar esta fotografâ”śÂˇa Lucien Roisin, en su puerta figuraba la inscripciâ”śâ”‚n "Almacâ”śÂ®n de cereales Pardina". Fuente visual: Zaragoza aâ”śâ–’os veinte. 81 fotografâ”śÂˇas de Roisin (1925-1931), IFC.', 1926, 1926, 1926, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65786700, -0.88343300, '0101000020E61000001FA166481545ECBF0F0F61FC34D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020930688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020930688.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020930688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21496, 'Casa Consistorial. Aâ”śâ–’os 20', 'El Convento de Santo Domingo de la Orden de Predicadores de Zaragoza fue fundado por Jaime I. El Refectorio fue construido en el s. XIV y su importancia era tal que las Cortes del Reino se reunieron varias veces en â”śÂ®l (ss. XIV-XV). La iglesia conventual fue reedificada en el XVII a la forma barroca, enorme, la tercera en tamaâ”śâ–’o tras El Pilar y La Seo. Las leyes desamortizadoras vaciaron el Convento, que pasâ”śâ”‚ a manos municipales. El templo fue demolido para ensanchar la calle de la Democracia, y para instalar el Asilo Municipal. Otras dependencias fueron convertidas en almacenes. En 1888 se instala un Colegio Preparatorio Militar (uno de los cuatro de todo el Estado), y se piquetea todo menos el Refectorio, que se inserta dentro del nuevo edificio, ideado por Ricardo Magdalena. Inaugurado en 1890, este colegio militar estuvo funcional hasta 1892. Luego fue Museo de Bellas Artes, y desde 1912, Casa Consistorial, hasta 1965. En la imagen, puerta principal, situada en la calle de la Democracia, con buenas vistas a la plaza de Santo Domingo, desde donde se ha hecho la foto.', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65800400, -0.88891600, '0101000020E610000030849CF7FF71ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15341739245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15341739245.webp', 'https://www.flickr.com/photos/zaragozaantigua/15341739245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21499, 'Arboleda de Macanaz 1923', 'AHPZ. Archivo fotogrâ”śĂ­fico Julio Requejo. 12/12/1923. "En la arboleda." Imagen de la arboleda de Macanaz, con vista al fondo de "Manufacturas de lanas de Morâ”śâ”‚n y Anâ”śâ”‚s", factorâ”śÂˇa diseâ”śâ–’ada por Miguel â”śĂĽngel Navarro. Los paseantes de la arboleda, en dâ”śÂˇa de ciercera, tienen al râ”śÂˇo a sus espaldas, y se dirigen al Camino de Ranillas, en un entorno que un par de aâ”śâ–’os despuâ”śÂ®s (1925) serâ”śĂ­ ocupado por el Centro Nataciâ”śâ”‚n Helios. De todo el conjunto fabril, supervive la que durante muchos aâ”śâ–’os fue "La Chimenea".', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.66024000, -0.88416300, '0101000020E6100000F8A92A34104BECBF6AC18BBE82D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15402888782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15402888782.webp', 'https://www.flickr.com/photos/zaragozaantigua/15402888782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21532, 'Patâ”śÂˇbulo 1922', 'Dibujo de Dâ”śÂˇaz Domâ”śÂˇnguez, 1922. Aunque las ejecuciones zaragozanas se habâ”śÂˇan hecho tradicionalmente en el pellerich de la plaza del Mercado, en el siglo XIX se decidiâ”śâ”‚ separar el lugar de comercio de viandas y el de matacâ”śÂˇa de humanos, trasladando el patâ”śÂˇbulo a las traseras de la câ”śĂ­rcel de Predicadores, en el paseo del Ebro. Los reos eran conducidos por la calle de la Triperâ”śÂˇa, atravesaban el Arco de San Ildefonso y subâ”śÂˇan al entarimado de la imagen. En este lugar tambiâ”śÂ®n se habâ”śÂˇan producido fusilamientos masivos a principios del siglo XIX. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65812400, -0.88523600, '0101000020E610000049BDA772DA53ECBF3A5B40683DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19436568684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19436568684.webp', 'https://www.flickr.com/photos/zaragozaantigua/19436568684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23167, 'Basilio Paraâ”śÂˇso 2009', 'Foto: Toni Galâ”śĂ­n. Inauguraciâ”śâ”‚n del busto de Basilio Paraâ”śÂˇso (empresario y polâ”śÂˇtico regeneracionsta aragonâ”śÂ®s, 1849-1930), obra de Florencio de Pedro, el 22 de enero de 2009. Se situâ”śâ”‚ junto a la entrada de la Câ”śĂ­mara de Comercio e Industria de Zaragoza, en el paseo de Isabel la Catâ”śâ”‚lica 2, siendo trasladado a la reformada plaza de Basilio Paraâ”śÂˇso en diciembre de 2012. En la foto, familiares del homenajeado posan con Juan Alberto Belloch, alcalde de Zaragoza; Marcelino Iglesias, presidente del gobierno de Aragâ”śâ”‚n; y Manuel Teruel, presidente de la Câ”śĂ­mara de Comercio. A estos â”śâ•‘ltimos se les distingue porque no llevan abrigo. Fuente: Heraldo de Aragâ”śâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'UNIVERSIDAD', 41.63732400, -0.89877800, '0101000020E61000003FA88B14CAC2ECBF5B7A34D593D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32916311906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32916311906.webp', 'https://www.flickr.com/photos/zaragozaantigua/32916311906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21581, 'Chalet Helios 1925', 'Imagen del original "chalet" que formâ”śâ”‚ parte de las primeras y precarias instalaciones de la "Sociedad Naturista Helios". Durante la sobresaliente riada del Ebro de 1930, este chalet asemejaba mâ”śĂ­s un lacustre palafito, rodeado de agua. Con el tiempo, irâ”śÂˇan tomando forma otras instalaciones naturistas: un gimnasio, un campo de tennis, otro de juego de pelota, duchas, columpios, y un estanque. En la imagen, y tras el edificio, y la natural valla, el camino de acceso que provenâ”śÂˇa, por la derecha, de la arboleda de Macanaz. A su derecha, e inmediato, se levantarâ”śĂ­ mâ”śĂ­s tarde un pabellâ”śâ”‚n para vestuarios, y el tablâ”śâ”‚n que desciende de su puerta de acceso serâ”śĂ­ sustituido por unas escaleras mâ”śĂ­s consistentes que desembocaban en una cancha de basket. Mâ”śĂ­s tarde, tras una de las sucesivas ampliaciones del ya redenominado y exitoso "Centro Nataciâ”śâ”‚n Helios", este chalet se convirtiâ”śâ”‚ en resto arqueolâ”śâ”‚gico.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65996200, -0.88450500, '0101000020E610000059C0046EDD4DECBF274D83A279D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24400351970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24400351970.webp', 'https://www.flickr.com/photos/zaragozaantigua/24400351970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21667, 'Plaza de Santo Domingo 1930', '"El Ayuntamiento" (Plaza de Santo Domingo).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65797200, -0.88904500, '0101000020E6100000A583F57F0E73ECBF84D72E6D38D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688633890.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688633890.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688633890/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21681, 'Puente del ferrocarril 1936', 'AHPZ-Archivo Coyne, Manuel Coyne, 1936. Puente del ferrocarril sobre el râ”śÂˇo Ebro.', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.66145000, -0.89009600, '0101000020E6100000029D499BAA7BECBF38F8C264AAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877669251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877669251.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877669251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21684, 'Santa Lucâ”śÂˇa 1930', '"Iglesia de Santa Lucâ”śÂˇa".', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65794000, -0.88964500, '0101000020E6100000F29881CAF877ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14895193433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14895193433.webp', 'https://www.flickr.com/photos/zaragozaantigua/14895193433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21688, 'Cincomarzada 1930', 'Vecinos del barrio de San Pablo celebran la Cincomarzada en la arboleda de Macanaz, con el fondo de las instalaciones de la fâ”śĂ­brica de Manufacturas de lanas de Morâ”śâ”‚n y Anâ”śâ”‚s".', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65954300, -0.89020900, '0101000020E61000000C5BB395977CECBF22A7AFE76BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15000345448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15000345448.webp', 'https://www.flickr.com/photos/zaragozaantigua/15000345448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21756, 'Callejâ”śâ”‚n del Arpa 1934', 'Imagen del callejâ”śâ”‚n denominado "Arpa" y, al fondo, la antigua posada de San Jerâ”śâ”‚nimo. Esta posada, sita en un caserâ”śâ”‚n rodeado de viviendas recayentes a la calle Bonaire (luego, Aben-Aire) por el norte, y Predicadores (luego, Democracia), por el sur, tenâ”śÂˇa en este "sombrâ”śÂˇo" callejâ”śâ”‚n su entrada y salida desde la calle Predicadores-Democracia. Desde antiguo, las calles del entorno de la plaza del Mercado estaban bien surtidas de mesones (luego, posadas) como este, desde la ribera del Ebro, y hasta la calle Doncellas, junto al convento de San Ildefonso. Esta zona de la imagen, ademâ”śĂ­s, formâ”śâ”‚ parte del "Burdel Viejo" de la ciudad. Fuente visual: A. de la Barrera, revista "Estampa" (Madrid).', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65724100, -0.88315500, '0101000020E61000006D904946CE42ECBF904B1C7920D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22567758507.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22567758507.webp', 'https://www.flickr.com/photos/zaragozaantigua/22567758507/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21770, 'Râ”śÂˇo Ebro c.1930', 'Postal editada por la Uniâ”śâ”‚n Postal Universal con imagen de las barcazas que cruzaban el Ebro en el tramo entre el puente de Piedra y la "Caseta de Baâ”śâ–’os", a travâ”śÂ®s de tres embarcaderos. Esta navegaciâ”śâ”‚n tenâ”śÂˇa carâ”śĂ­cter funcional (conectar ambas riberas), y recreativo (acceso râ”śĂ­pido a la arboleda de Macanaz). Fuente visual: www.delcampe.net/', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65896600, -0.88306900, '0101000020E6100000C99063EB1942ECBF859675FF58D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22829128757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22829128757.webp', 'https://www.flickr.com/photos/zaragozaantigua/22829128757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21786, 'Calle de los Infantes c.1930', 'Imagen de la original calle de los Infantes de San Pablo, con entrada por la calle de Aben-Aire, y sin salida. Paralela a las calles de Predicadores, al sur, y a la mâ”śĂ­s pequeâ”śâ–’a de Constantino, al norte. Los edificios son construcciones seriadas levantadas en el siglo XVIII, de alquiler. La imagen ha sido realizada casi al comienzo de la calle, mirando hacia el lado de los pares. A mediados de los aâ”śâ–’os 70 del pasado siglo, toda esta zona padeciâ”śâ”‚ una intervenciâ”śâ”‚n radical, incluyendo la demoliciâ”śâ”‚n de todo lo que aparece en imagen. Sic transit gloria urbis. Fuente visual: AMZ.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65762100, -0.88373300, '0101000020E6100000C5ABAC6D8A47ECBFD714C8EC2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23247884096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23247884096.webp', 'https://www.flickr.com/photos/zaragozaantigua/23247884096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21823, 'Embarcadero Ebro c.1930', 'Imagen capturada desde las inmediaciones de la pâ”śâ•‘blica Caseta de los Baâ”śâ–’os de la margen izquierda, junto a la Sociedad Naturista "Helios", del mâ”śĂ­s occidental de los tres embarcaderos habilitados para acceso a la zona recreativa de la arboleda de Macanaz. La aâ”śÂ®rea sirga conectaba con uno de los dos embarcaderos de la margen derecha, en el paseo del Ebro, escalonados cerca del acceso a la calle de Antonio Pâ”śÂ®rez. Fuente visual: Arxiu Nacional de Catalunya', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65896600, -0.88306900, '0101000020E6100000C99063EB1942ECBF859675FF58D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32050239495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32050239495.webp', 'https://www.flickr.com/photos/zaragozaantigua/32050239495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21098, 'Puente de Piedra c.1881', 'Fondo Documental Histâ”śâ”‚rico de las Cortes de Aragâ”śâ”‚n. (ca. 1880). Puente de Piedra de Zaragoza.', 1881, 1881, 1881, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65704200, -0.87541900, '0101000020E61000003881E9B46E03ECBF990CC7F319D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14874431941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14874431941.webp', 'https://www.flickr.com/photos/zaragozaantigua/14874431941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21826, 'Postigo del Ebro 1930', 'Imagen del antiguo desemboque, en descenso, de la calle del Postigo del Ebro en el paseo del Ebro. Al fondo, el arranque de esta calle desde la de la Democracia, antigua de Predicadores, que tras el 18 de julio de 1936 recuperâ”śâ”‚ esa denominaciâ”śâ”‚n. El nombre de Postigo del Ebro es un recuerdo del antiguo "postigo", o paso, que por esta calle abrâ”śÂˇa el antiguo barrio de la Poblaciâ”śâ”‚n del Rey, o de San Pablo, hacia la ribera del râ”śÂˇo. La caseta de madera de la izquierda es una rememoranza de cuando el trâ”śĂ­nsito por estos pasos estaba vigilado. Como indica el cartel, a Barcelona se va por la izquierda (segâ”śâ•‘n se mire). Fuente visual: Miguel Marâ”śÂˇn Chivite, periâ”śâ”‚dico "Heraldo de Aragâ”śâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65820600, -0.88621100, '0101000020E6100000E55FCB2BD75BECBFF7031E1840D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32541554445.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32541554445.webp', 'https://www.flickr.com/photos/zaragozaantigua/32541554445/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21837, 'Convento de Santa Lucâ”śÂˇa c.1935', 'Imagen centrada en el interior del exclusivo y poligonal â”śĂ­bside de cinco lados de la iglesia del antiguo convento cisterciense de Santa Lucâ”śÂˇa, una irrepetible muestra del gâ”śâ”‚tico-mudâ”śÂ®jar desaparecido durante la prodigiosa dâ”śÂ®cada de los aâ”śâ–’os sesenta del pasado siglo. Esta iglesia conventual estaba ubicada entre la calle de Santa Lucâ”śÂˇa, y la plaza de Santo Domingo, y lucâ”śÂˇa estas enrevesadas trazas desde que fueron compuestas posiblemente a finales del siglo XVI. Como en otros casos, estaba incluida en el catâ”śĂ­logo del mudâ”śÂ®jar local mâ”śĂ­s selecto, hasta que fue vendida y derribada. Fuente visual: Francisco Abbad Râ”śÂˇos. "Guâ”śÂˇas artâ”śÂˇsticas de Espaâ”śâ–’a. Zaragoza" (1952).', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65804100, -0.88976500, '0101000020E61000009B030473F478ECBFAC36FFAF3AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34733019320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34733019320.webp', 'https://www.flickr.com/photos/zaragozaantigua/34733019320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21954, 'Puente del Ferrocarril 1946', 'Desde la alameda de Macanaz, cerca de la confluencia de la antigua acequia de la Ortilla en el râ”śÂˇo Ebro, imagen del Puente del Ferrocarril. Inaugurado en 1870, fue recrecido en altura en 1879 tras comprobar que las riadas de este râ”śÂˇo, cuando vienen, no son cualesquiera cosa. La imagen muestra que ese recrecimiento fue muy necesario. A nuestras espaldas queda el Centro Nataciâ”śâ”‚n Helios, que se habâ”śÂˇa cambiado de nombre hacâ”śÂˇa poco (hasta 1942 fue "Centro Naturista Helios"). Al otro lado del râ”śÂˇo, tras el puente, construcciones en torno al antiguo Camino de la Almozara, las calles Padre Landa y Juan Sariâ”śâ–’ena. La presencia de la gigante "Quâ”śÂˇmica", a la izquierda, fuera de plano, determinaba una barriada esencialmente industriosa, mâ”śĂ­s allâ”śĂ­ de donde estuviera la Puerta y el Molino de Sancho. A la derecha, el denso Soto de la Almozara. Al aâ”śâ–’o siguiente de esta imagen, el Puente del Ferrocarril serâ”śĂ­ modificado para aâ”śâ–’adirle un segundo tablero reforzado que permitirâ”śĂ­ la doble direcciâ”śâ”‚n a unas locomotoras de vapor mâ”śĂ­s potentes y pesadas. Este puente seguirâ”śĂ­ prestando servicio ferroviario hasta 1976, cuando tras el desmantelamiento de la lâ”śÂˇnea de enlace, sea reformado para trâ”śĂ­fico viario a motor de explosiâ”śâ”‚n. En la imagen, un convoy arrastrado por una "vaporosa", se encamina traqueteando hacia la veterana Estaciâ”śâ”‚n del Norte. Fuente visual: fotografâ”śÂˇa de Mariano Lacruz Berdejo, amablemente aportada por Mariano Lacruz Pâ”śÂ®rez (Archivo Familia Lacruz Pâ”śÂ®rez).', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.66154300, -0.88990800, '0101000020E61000004F5C8E57207AECBFE9F2E670ADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19457423573.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19457423573.webp', 'https://www.flickr.com/photos/zaragozaantigua/19457423573/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22010, 'Torre de San Pablo c.1945', '"Râ”śÂˇo", pintura de Jesâ”śâ•‘s Fernâ”śĂ­ndez Barrio, aâ”śâ–’os 40. Vista de la torre de San Pablo desde la margen izquierda del râ”śÂˇo Ebro. Fuente: fernandezbarrio.es', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65901700, -0.88521400, '0101000020E610000054C37E4FAC53ECBF074147AB5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40737002754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40737002754.webp', 'https://www.flickr.com/photos/zaragozaantigua/40737002754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22043, 'Municipales motorizados 1955', 'Ayuntamiento de Zaragoza/Marâ”śÂˇn Chivite. 17 de septiembre de 1955. La Secciâ”śâ”‚n Motorista de la Policâ”śÂˇa Municipal es presentada en sociedad en la Plaza de Santo Domingo, junto al Ayuntamiento. De fondo, a la derecha, el edificio del Mercado de Pescados, construido en 1928. A la izquierda, acceso a la calle de las Armas.', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65738600, -0.88899600, '0101000020E61000004BCB48BDA772ECBF946C753925D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14758346159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14758346159.webp', 'https://www.flickr.com/photos/zaragozaantigua/14758346159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22055, 'Fernando Rey 1951', 'Ayuntamiento de Zaragoza/Marâ”śÂˇn Chivite. 6 de mayo de 1951. Acto de imposiciâ”śâ”‚n de la medalla de plata de Zaragoza al actor Fernando Rey por su interpretaciâ”śâ”‚n de Palafox en la pelâ”śÂˇcula "Agustina de Aragâ”śâ”‚n". Aurora Bautista, que hacâ”śÂˇa de Agustina, atenta a la imposiciâ”śâ”‚n. Impone Josâ”śÂ® Marâ”śÂˇa Garcâ”śÂˇa Belenguer, alcalde de la ciudad entre 1949 y 1954.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65798800, -0.88890000, '0101000020E6100000C442AD69DE71ECBF8A9466F338D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14916457916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14916457916.webp', 'https://www.flickr.com/photos/zaragozaantigua/14916457916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22056, 'Aurora Bautista 1951', 'Ayuntamiento de Zaragoza/Marâ”śÂˇn Chivite. 6 de mayo de 1951. Acto de imposiciâ”śâ”‚n de la medalla de plata de Zaragoza a la actriz Aurora Bautista. Fue concedida por la corporaciâ”śâ”‚n por su interpretaciâ”śâ”‚n del papel de Agustina Zaragoza en la pelâ”śÂˇcula "Agustina de Aragâ”śâ”‚n". Impone Josâ”śÂ® Marâ”śÂˇa Garcâ”śÂˇa Belenguer, alcalde de la ciudad entre 1949 y 1954.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65800400, -0.88891600, '0101000020E610000030849CF7FF71ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14916507946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14916507946.webp', 'https://www.flickr.com/photos/zaragozaantigua/14916507946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22144, 'Convento de Santa Lucâ”śÂˇa c.1950', 'Imagen de los huertos interiores del antiguo convento de Santa Lucâ”śÂˇa, en la calle de los Predicadores. A la izquierda, la nave de la iglesia conventual gâ”śâ”‚tico-mudâ”śÂ®jar, modificada en el siglo XVI, y la espadaâ”śâ–’a de su demediada torre. Tras ella, una pequeâ”śâ–’a chimenea de la Azucarera Agrâ”śÂˇcola del Pilar, antigua alcoholera. Los edificios del centro son recayentes a la plaza de Santo Domingo, y al edificio del Ayuntamiento, que sobresale al fondo. Este conjunto conventual fue vendido y derribado a finales de la prodigiosa dâ”śÂ®cada de los aâ”śâ–’os 60 del pasado siglo, ad maiorem dei gloriam. En su lugar se construyeron interesantes moles edilicias que dignifican el patrimonio urbano hasta extremos irreproducibles. La poca calidad de la inâ”śÂ®dita imagen refuerza el sentido onâ”śÂˇrico, irreal, de una antigua zona cuya mutaciâ”śâ”‚n ha sido, cuando menos, antolâ”śâ”‚gica. Fuente visual: "La arquitectura aragonesa del siglo XVI", Javier Ibâ”śĂ­â”śâ–’ez Fernâ”śĂ­ndez, IFC.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65794000, -0.88964500, '0101000020E6100000F29881CAF877ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25692240204.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25692240204.webp', 'https://www.flickr.com/photos/zaragozaantigua/25692240204/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23969, 'Pabellâ”śâ”‚n Francâ”śÂ®s 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Junio 1966. Imagen del "Primer Congreso Diocesano de hombres catâ”śâ”‚licos" en el Pabellâ”śâ”‚n Francâ”śÂ®s de la Feria de Muestras, customizado para la ocasiâ”śâ”‚n.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63755100, -0.90001500, '0101000020E6100000221ADD41ECCCECBF1C446B459BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15097624994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15097624994.webp', 'https://www.flickr.com/photos/zaragozaantigua/15097624994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24079, 'Parque Primo de Rivera 1967', 'Imagen capturada durante la inauguraciâ”śâ”‚n oficial del monumento al nicaragâ”śâ•ťense Fâ”śÂ®lix Rubâ”śÂ®n Sarmiento (Rubâ”śÂ®n Darâ”śÂˇo) realizado en piedra y bronce por el escultor â”śĂĽngel Orensanz y emplazado en la rosaleda del parque de Primo de Rivera con motivo del centenario del nacimiento de este poeta. Centran el posado el alcalde de Zaragoza, Cesâ”śĂ­reo Alierta, y el embajador de Nicaragua, Vicente Urcuyo. Junto a ellos, embajadores de Colombia, Costa Rica, Honduras y Panamâ”śĂ­, y representantes de diversas instancias diplomâ”śĂ­ticas y culturales. Fuente visual: Jarke/Jaria, AMZ.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.63287100, -0.89624200, '0101000020E6100000F8A6E9B303AEECBF1DCBBBEA01D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38525505421.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38525505421.webp', 'https://www.flickr.com/photos/zaragozaantigua/38525505421/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22489, 'Convento de Santo Domingo 1967', 'Imagen capturada en el interior del antiguo refectorio del convento de los frailes predicadores de Santo Domingo, cuando todavâ”śÂˇa era utilizado como archivo-biblioteca municipal, tal y como venâ”śÂˇa siendo desde que la Casa Consistorial estuviera ubicada en las inmediatas dependencias de la Plaza de Santo Domingo, en el edificio de la antigua Academia Preparatoria Militar de Zaragoza. Este espacio gâ”śâ”‚tico-mudâ”śÂ®jar fue construido en los inicios del siglo XIV como refectorio (comedor) del gran convento de los predicadores, segâ”śâ•‘n factura llevada a cabo en piedra y ladrillo por los alarifes mudâ”śÂ®jares de la familia Bellito. Consta de una sala rectangular distribuida en dos naves divididas en cinco tramos, con columnas de piedra que soportan una bâ”śâ”‚veda de crucerâ”śÂˇa. En el siglo XIX fue objeto de reformas por el arquitecto Ricardo Magdalena, como los grandes â”śâ”‚culos sobre los apuntados ventanales de la derecha (con orientaciâ”śâ”‚n sur), que originalmente ademâ”śĂ­s se abrâ”śÂˇan al claustro principal del convento, espacio central junto al cual tambiâ”śÂ®n estaba adosada la gran iglesia. El estucado y pintura que oculta los ladrillos de paredes y bâ”śâ”‚vedas era tambiâ”śÂ®n signo de las modas imperantes cuando aquella intervenciâ”śâ”‚n. Fuente visual: fotografâ”śÂˇa de Guillermo Fatâ”śĂ­s Ojuel en Torralba, Federico; Gâ”śâ”‚mez de Valenzuela, Manuel, Catâ”śĂ­logo de monumentos histâ”śâ”‚ricos-artâ”śÂˇsticos y edificios de interâ”śÂ®s para el estudio del arte en la ciudad de Zaragoza. Cuadernos de Aragâ”śâ”‚n nâ”¬â•‘ 73, IFC.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65845500, -0.88865700, '0101000020E61000002E910BCEE06FECBF9F71E14048D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44186002854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44186002854.webp', 'https://www.flickr.com/photos/zaragozaantigua/44186002854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22584, 'Regatas Ebro 1970', 'Archivo Municipal. Gerardo Sancho Ramo. Setiembre 1970. Unas emotivas regatas deportivas sobre el Ebro pueden servir, tal es el caso, para capturar una muy interesante visual de los edificios de la margen derecha, o mâ”śĂ­s bien de los restos de los edificios que una vez hubo, entre el colegio Valentâ”śÂˇn Zabala (a la izquierda), y el antiguo palacio de los Duques de Villahermosa (s. XVII) utilizado luego como câ”śĂ­rcel, juzgados, y câ”śĂ­rcel de mujeres durante el franquismo. La emergencia de la torre de la iglesia de San Pablo, y de uno de los torreones del palacio aclaran bastante la perspectiva, aunque resulta absolutamente incomparable con la actualidad pues, salvo la torre y el torreâ”śâ”‚n, ningâ”śâ•‘n elemento de este panorama supervive.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65786700, -0.88343300, '0101000020E61000001FA166481545ECBF0F0F61FC34D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15612789918.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15612789918.webp', 'https://www.flickr.com/photos/zaragozaantigua/15612789918/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22657, 'Puente del ferrocarril 1978', 'El original Puente del Ferrocarril sobre el Ebro prestâ”śâ”‚ servicio, con modificaciones, ampliaciones y recrecimiento incluido, desde 1870 y hasta 1976. Luego serâ”śĂ­ reformado para el prioritario trâ”śĂ­fico viario a motor de explosiâ”śâ”‚n. En la imagen, el puente ya desmantelado de elementos ferroviarios, capturado desde la margen izquierda. Al fondo, la ciudad con el punto de encuentro del barrio de San Pablo, con el de la Quâ”śÂˇmica, o Almozara. En medio, sobresale el llamativo cartel de Piensos "Cia". Fuente visual: Archivo Pâ”śâ•‘blico Municipal, Gerardo Sancho Ramo.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.66209200, -0.88962400, '0101000020E6100000149337C0CC77ECBFBC783F6EBFD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21845314095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21845314095.webp', 'https://www.flickr.com/photos/zaragozaantigua/21845314095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22719, 'Râ”śÂˇo Ebro 1979', 'Foto: Tomâ”śĂ­s Mora. Imagen nocturna tomada desde la plaza de Santo Domingo, con el paseo de Echegaray y Caballero en primer tâ”śÂ®rmino y las instalaciones del Club Helios al otro lado del Ebro. Fuente: www.facebook.com/photo.php?fbid=1439169236111190&set=...', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65862600, -0.88838100, '0101000020E6100000A968ACFD9D6DECBFCC2555DB4DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30138428323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30138428323.webp', 'https://www.flickr.com/photos/zaragozaantigua/30138428323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
