INSERT INTO public.photos VALUES (22884, 'Calle Predicadores 1987', 'En 1987 se derribaron las casas de los entonces nâ”śâ•‘meros 20 al 30 de la calle de Predicadores de Zaragoza. La normativa vigente exigâ”śÂˇa la realizaciâ”śâ”‚n de catas arqueolâ”śâ”‚gicas, que fueron solicitadas pâ”śâ•‘blicamente por Guillermo Fatâ”śĂ­s y realizadas pese a las urgencias constructivas del Ayuntamiento presidido por Antonio Gonzâ”śĂ­lez Triviâ”śâ–’o. Un equipo dirigido por Marâ”śÂˇa Pilar Galve sacâ”śâ”‚ a la luz la romana Necrâ”śâ”‚polis occidental de Caesaraugusta, del siglo III, ademâ”śĂ­s de constatar que en la zona (periferia de la ciudad, mâ”śĂ­s allâ”śĂ­ de la Puerta de Toledo) se produjeron enterramientos musulmanes hasta el siglo X. El hallazgo mâ”śĂ­s relevante fue un mausoleo, en el solar de los nâ”śâ•‘meros 24-26, esquina derecha con la calle de Abâ”śÂ®n Aire. Este pequeâ”śâ–’o monumento, â”śâ•‘nico en la ciudad, merecâ”śÂˇa ser conservado en opiniâ”śâ”‚n de los arqueâ”śâ”‚logos, pero no lo fue, siguiendo el criterio de los entonces responsables polâ”śÂˇticos. En la foto, en primer plano, el mausoleo hoy destruido, nâ”śâ•‘cleo al que se fueron aglutinando las demâ”śĂ­s inhumaciones de la zona. Fuente: Marâ”śÂˇa Pilar Galve Izquierdo, La necrâ”śâ”‚polis occidental de Caesaraugusta en el siglo III, 2008.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65732100, -0.88355200, '0101000020E6100000B1170AD80E46ECBFADFC321823D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19759420659.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19759420659.webp', 'https://www.flickr.com/photos/zaragozaantigua/19759420659/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
